# This is the detectors map used for VQWK checks


[QwHelicity]
 name = Helicity Info
 map  = mock_moller_helicity.map

[QwBeamLine]
 name     = Main BeamLine
 map      = mock_moller_beamline.map
 param    = mock_moller_beamline_pedestal.map
 geom     = mock_moller_beamline_geometry.map
 eventcut = mock_moller_beamline_eventcuts.map

[QwBeamLine]
 name  = Injector BeamLine
 map   = mollinj_beamline.map
 param = mollinj_beamline_pedestal.map
 geom  = mollinj_beamline_geometry.map
 eventcut = mollinj_beamline_eventcuts.map

[QwDetectorArray]
 name  = Thin Quartz Detector
 map   = mock_moller_thinqtz_adc.map
 param = mock_moller_thinqtz_pedestal.map
 eventcut = mock_moller_thinqtz_eventcuts.map

[QwDetectorArray]
 name  = Shower Max Detector
 map   = mock_moller_shrmax_adc.map
 param = mock_moller_shrmax_pedestal.map
 eventcut = mock_moller_shrmax_eventcuts.map

[QwDetectorArray]
 name  = Pion Detector
 map   = mock_moller_piondet_adc.map
 param = mock_moller_piondet_pedestal.map
 eventcut = mock_moller_piondet_eventcuts.map

[QwDetectorArray]
 name  = Small Angle Detector
 map   = mock_moller_smallang_adc.map
 param = mock_moller_smallang_pedestal.map
 eventcut = mock_moller_smallang_eventcuts.map

[QwDetectorArray]
 name  = Large Angle Detector
 map   = mock_moller_largeang_adc.map
 param = mock_moller_largeang_pedestal.map
 eventcut = mock_moller_largeang_eventcuts.map
